def perceive(data):
    text = data if isinstance(data, str) else str(data)
    for ch in ("=", ":", ",", ";", "\n", "\t"):
        text = text.replace(ch, " ")
    toks = text.split()
    fields = {"supply", "demand", "frequency"}
    out = {}
    for i in range(len(toks) - 1):
        key = toks[i].strip().lower()
        if key in fields:
            try:
                out[key] = float(toks[i + 1])
            except ValueError:
                pass
    return out
